14560                                  MaxDepthLevel, NeedToDemote, IsTruncRoot) ||
14561           (MaxDepthLevel <= Limit &&
14562            !(((Opcode == Instruction::SExt || Opcode == Instruction::ZExt) &&
14563               (!IsTopRoot || !(IsStoreOrInsertElt || UserIgnoreList) ||
14564                DL->getTypeSizeInBits(Root->getType()) /
14565                        DL->getTypeSizeInBits(
14566                            cast<Instruction>(Root)->getOperand(0)->getType()) >
14567                    2)))))
14568         return 0u;
14569     }
14570     // Round MaxBitWidth up to the next power-of-two.
14571     MaxBitWidth = bit_ceil(MaxBitWidth);
14572 
14573     return MaxBitWidth;
14574   };
