14588       auto Mask = DB->getDemandedBits(cast<Instruction>(V));
14589       unsigned BitWidth2 = Mask.getBitWidth() - Mask.countl_zero();
14590       ReductionBitWidth =
14591           std::max(std::min(BitWidth1, BitWidth2), ReductionBitWidth);
14592     }
14593     if (ReductionBitWidth < 8 && ReductionBitWidth > 1)
14594       ReductionBitWidth = 8;
14595 
14596     ReductionBitWidth = bit_ceil(ReductionBitWidth);
14597   }
14598   bool IsTopRoot = NodeIdx == 0;
14599   while (NodeIdx < VectorizableTree.size() &&
14600          VectorizableTree[NodeIdx]->State == TreeEntry::Vectorize &&
