14608     unsigned Limit = 2;
14609     unsigned Opcode = VectorizableTree[NodeIdx]->getOpcode();
14610     if (IsTopRoot &&
14611         ReductionBitWidth ==
14612             DL->getTypeSizeInBits(
14613                 VectorizableTree.front()->Scalars.front()->getType()))
